import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const RoomMaster = () => {
    const [rooms, setRooms] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [blocks, setBlocks] = useState([]);
    const [formData, setFormData] = useState({ department: '', programme: '', block: '', roomNumber: '' });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchRooms();
        fetchDepartments();
    }, []);

    const fetchRooms = async () => {
        try {
            const { data } = await API.get('/master/room');
            setRooms(data);
        } catch (err) {
            alert('Error fetching rooms');
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            alert('Error fetching departments');
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            alert('Error fetching programmes');
        }
    };

    const fetchBlocks = async (progId) => {
        try {
            const { data } = await API.get('/master/block');
            const filtered = data.filter(b => b.programme && b.programme._id === progId);
            setBlocks(filtered);
        } catch (err) {
            alert('Error fetching blocks');
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData({...formData, department: deptId, programme: '', block: ''});
        fetchProgrammes(deptId);
    };

    const handleProgrammeChange = (e) => {
        const progId = e.target.value;
        setFormData({...formData, programme: progId, block: ''});
        fetchBlocks(progId);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/room', formData);
            setFormData({ department: '', programme: '', block: '', roomNumber: '' });
            fetchRooms();
            alert('Room added successfully!');
        } catch (err) {
            alert('Error adding room');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Room Number Master</h2>
            
            <form onSubmit={handleSubmit} style={{ maxWidth: '500px', marginBottom: '40px' }}>
                <div style={{ marginBottom: '15px' }}>
                    <label>Department</label>
                    <select 
                        required
                        value={formData.department}
                        onChange={handleDepartmentChange}
                        style={inputStyle}
                    >
                        <option value="">Select Department</option>
                        {departments.map(dept => (
                            <option key={dept._id} value={dept._id}>{dept.department}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Programme</label>
                    <select 
                        required
                        value={formData.programme}
                        onChange={handleProgrammeChange}
                        style={inputStyle}
                    >
                        <option value="">Select Programme</option>
                        {programmes.map(prog => (
                            <option key={prog._id} value={prog._id}>{prog.programme}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Block</label>
                    <select 
                        required
                        value={formData.block}
                        onChange={e => setFormData({...formData, block: e.target.value})}
                        style={inputStyle}
                    >
                        <option value="">Select Block</option>
                        {blocks.map(blk => (
                            <option key={blk._id} value={blk._id}>{blk.blockName}</option>
                        ))}
                    </select>
                </div>
                
                <div style={{ marginBottom: '15px' }}>
                    <label>Room Number</label>
                    <input 
                        type="text" 
                        placeholder="e.g., 123"
                        required
                        value={formData.roomNumber}
                        onChange={e => setFormData({...formData, roomNumber: e.target.value})}
                        style={inputStyle}
                    />
                </div>

                <button type="submit" disabled={loading} style={btnStyle}>
                    {loading ? 'Adding...' : 'Add Room'}
                </button>
            </form>

            <h3>Rooms List</h3>
            <table style={tableStyle}>
                <thead>
                    <tr>
                        <th>Department</th>
                        <th>Programme</th>
                        <th>Block</th>
                        <th>Room Number</th>
                    </tr>
                </thead>
                <tbody>
                    {rooms.map(room => (
                        <tr key={room._id}>
                            <td>{room.department?.department}</td>
                            <td>{room.programme?.programme}</td>
                            <td>{room.block?.blockName}</td>
                            <td>{room.roomNumber}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const btnStyle = { 
    padding: '12px 20px', 
    background: 'linear-gradient(to right, #38bdf8, #818cf8)', 
    border: 'none', 
    borderRadius: '5px', 
    color: 'white', 
    fontWeight: 'bold', 
    cursor: 'pointer',
    width: '100%'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    marginTop: '20px',
    border: '1px solid #334155'
};

export default RoomMaster;
